parameters.jsCode:
let codeToCheck = query || "";

// 1. Clean the code: Remove markdown backticks
codeToCheck = codeToCheck.replace(/```javascript/gi, '').replace(/```/g, '');

// 2. Diff Protocol Check: Extract only the NEW code if it's a Search/Replace block
if (codeToCheck.includes('====') && codeToCheck.includes('>>>>')) {
    const parts = codeToCheck.split('====');
    if(parts.length > 1) {
        codeToCheck = parts[1].split('>>>>')[0].trim();
    }
}

// 3. The Validation Engine
try {
    // new Function() parses the string using the V8 engine to check for syntax errors,
    // but it does not execute the code inside.
    new Function(codeToCheck);
    return "STATUS: PASS. Syntax is perfectly valid. You may output the code to the user.";
} catch (error) {
    return `STATUS: FAIL. Syntax Error found: ${error.message}\n\nPlease fix the exact line or token and validate again.`;
}

